import { z } from "zod";
export const tagColorEnum = z
.string()
.regex(/^#[0-9a-fA-F]{6}$/u, "Use a hex color like #aabbcc.")
.nullable()
.optional();
export const createTagSchema = z.object({
name: z.string().trim().min(1, "Tag name is required.").max(60),
color: tagColorEnum,
});
export const updateTagSchema = z.object({
name: z.string().trim().min(1).max(60).optional(),
color: tagColorEnum,
});
export const setNoteTagsSchema = z.object({
noteId: z.string().min(1),
tagIds: z.array(z.string()).max(50),
});
export type CreateTagInput = z.infer<typeof createTagSchema>;
export type UpdateTagInput = z.infer<typeof updateTagSchema>;
export type SetNoteTagsInput = z.infer<typeof setNoteTagsSchema>;

import { z } from "zod";
export const taskStatusEnum = z.enum(["todo", "doing", "done", "canceled"]);
export const taskPriorityEnum = z.enum(["none", "low", "medium", "high"]);
export const taskSourceEnum = z.enum(["manual", "markdown", "ai"]);
export const createTaskSchema = z.object({
noteId: z.string().min(1),
title: z.string().trim().min(1, "Task title is required.").max(300),
description: z.string().max(2_000).nullable().optional(),
status: taskStatusEnum.default("todo"),
priority: taskPriorityEnum.default("none"),
dueDate: z.coerce.date().nullable().optional(),
source: taskSourceEnum.default("manual"),
...
sourceLine: z.number().int().nullable().optional(),
});
export const updateTaskSchema = z.object({
title: z.string().trim().min(1).max(300).optional(),
description: z.string().max(2_000).nullable().optional(),
status: taskStatusEnum.optional(),
priority: taskPriorityEnum.optional(),
dueDate: z.coerce.date().nullable().optional(),
});
export type UpdateTaskInput = z.infer<typeof updateTaskSchema>;
